module RefModule(
    Q  ,
    CLK,
    D  ,
    SCD,
    SCE
);output Q  ;
    input  CLK;
    input  D  ;
    input  SCD;
    input  SCE;


reg q_reg;
wire mux_out;
wire __mux_out_tmp = (SCE == 1'b1)? SCD : D;
assign mux_out = __mux_out_tmp;

always @ ( posedge CLK)
       begin
	     q_reg <= mux_out;
       end

assign Q = q_reg;

endmodule
